<?php
declare(strict_types=1);
function booking_manage_url(array $booking):string{return rtrim((string)config('url'),'/').'/booking/'.$booking['cancel_token'];}
function booking_send_confirmation(int $bookingId,string $kind='confirmation'):void{$q=db()->prepare('SELECT b.*,m.name meeting_name,m.location_details,COALESCE(NULLIF(u.display_name,\'\'),u.username) host_name,u.email host_email FROM bookings b JOIN booking_meeting_types m ON m.id=b.meeting_type_id LEFT JOIN users u ON u.id=b.assigned_user_id WHERE b.id=?');$q->execute([$bookingId]);$b=$q->fetch();if(!$b)return;$when=(new DateTimeImmutable($b['starts_at'],new DateTimeZone($b['timezone'])))->format('l, F j, Y \a\t g:i A T');$subjects=['confirmation'=>'Meeting confirmed','rescheduled'=>'Meeting rescheduled','cancelled'=>'Meeting cancelled','reminder'=>'Meeting reminder','reminder_24h'=>'Meeting reminder — tomorrow','reminder_1h'=>'Meeting reminder — one hour'];$subject=($subjects[$kind]??'Booking update').': '.$b['meeting_name'];$body="Hello {$b['attendee_name']},\n\n{$subject}\n\nWhen: {$when}\nHost: ".($b['host_name']?:'OpenCRM')."\nLocation: ".($b['location_details']?:'To be provided')."\n\nManage this booking: ".booking_manage_url($b)."\n";try{crm_send_email($b['attendee_email'],$subject,$body);db()->prepare("INSERT INTO booking_notification_log(booking_id,notification_type,recipient,sent_at,status) VALUES(?,?,?,NOW(),'sent') ON DUPLICATE KEY UPDATE sent_at=NOW(),status='sent',error_message=NULL")->execute([$bookingId,$kind,$b['attendee_email']]);if($b['host_email'])crm_send_email($b['host_email'],$subject,"{$b['attendee_name']} ({$b['attendee_email']})\n\n".$body);}catch(Throwable $e){db()->prepare("INSERT INTO booking_notification_log(booking_id,notification_type,recipient,status,error_message) VALUES(?,?,?,'failed',?) ON DUPLICATE KEY UPDATE status='failed',error_message=VALUES(error_message)")->execute([$bookingId,$kind,$b['attendee_email'],mb_strimwidth($e->getMessage(),0,500)]);app_log('error','Booking email failed',['booking_id'=>$bookingId,'kind'=>$kind,'error'=>$e->getMessage()]);}}
function booking_schedule_reminders(int $bookingId):void{$q=db()->prepare('SELECT starts_at,attendee_email FROM bookings WHERE id=?');$q->execute([$bookingId]);$b=$q->fetch();if(!$b)return;foreach(['reminder_24h'=>24,'reminder_1h'=>1] as $kind=>$hours){$at=(new DateTimeImmutable($b['starts_at']))->modify("-$hours hours");if($at>new DateTimeImmutable())db()->prepare("INSERT IGNORE INTO booking_notification_log(booking_id,notification_type,recipient,scheduled_for,status) VALUES(?,?,?,?,'pending')")->execute([$bookingId,$kind,$b['attendee_email'],$at->format('Y-m-d H:i:s')]);}}
